import{_ as o,o as i,c as a,as as d}from"./chunks/framework.Dt0DMeWU.js";const s=JSON.parse('{"title":"第七章 远程工具的使用","description":"","frontmatter":{},"headers":[],"relativePath":"backend/Linux/07 第七章 远程工具的使用.md","filePath":"backend/Linux/07 第七章 远程工具的使用.md","lastUpdated":1775485159000}'),c={name:"backend/Linux/07 第七章 远程工具的使用.md"};function t(n,e,r,p,m,g){return i(),a("div",null,[...e[0]||(e[0]=[d('<h1 id="第七章-远程工具的使用" tabindex="-1">第七章 远程工具的使用 <a class="header-anchor" href="#第七章-远程工具的使用" aria-label="Permalink to &quot;第七章 远程工具的使用&quot;">​</a></h1><h2 id="学习目标" tabindex="-1">学习目标 <a class="header-anchor" href="#学习目标" aria-label="Permalink to &quot;学习目标&quot;">​</a></h2><p><code>1</code> 熟练安装和使用 <code>WindTerm</code></p><h2 id="第一节-windterm-的安装和使用" tabindex="-1">第一节 <code>WindTerm</code> 的安装和使用 <a class="header-anchor" href="#第一节-windterm-的安装和使用" aria-label="Permalink to &quot;第一节 `WindTerm` 的安装和使用&quot;">​</a></h2><blockquote><p><code>Linux</code> 一般作为服务器使用,服务器一般都放在机房,不可能是你身边的 <code>Linux</code> 服务器,这时候我们需要一些工具来连接远程的 <code>Linux</code> 服务器来进行操作,<code>WindTerm</code> 就是一种远程连接工具,其他 <code>Windows</code> 上常见的远程登录客户端有 <code>SecureCRT</code>, <code>Xshell</code>,<code>SSHSecure Shell</code>,等</p></blockquote><blockquote><p><code>Linux</code> 系统中是通过 <code>SSH</code> 服务 实现的远程登录功能,默认 <code>ssh</code> 服务的端口号是 <code>22</code></p></blockquote><h3 id="_1-1-下载-windterm" tabindex="-1"><code>1.1</code> 下载 <code>WindTerm</code> <a class="header-anchor" href="#_1-1-下载-windterm" aria-label="Permalink to &quot;`1.1` 下载 `WindTerm`&quot;">​</a></h3><p><code>WindTerm</code> 在 <code>GitHub</code> 的开源地址 ：<a href="https://github.com/kingToolbox/WindTerm" target="_blank" rel="noreferrer">https://github.com/kingToolbox/WindTerm</a> <code>WindTerm</code> 发布版本下载地址 ：<a href="https://github.com/kingToolbox/WindTerm/releases" target="_blank" rel="noreferrer">https://github.com/kingToolbox/WindTerm/releases</a> <code>WindTerm</code> 官网功能介绍：<a href="https://kingtoolbox.github.io/" target="_blank" rel="noreferrer">https://kingtoolbox.github.io/</a></p><p><strong>（<code>1</code>）点击 发布版本下载地址，跳转到发布版本页面，找到当前最新版本下载</strong></p><p><img src="https://img.xbin.cn/blog/image-20230626165250392.png" alt="image-20230626163815805"></p><p><strong>（<code>2</code>）下载 <code>windows</code> 版本</strong></p><p><img src="https://img.xbin.cn/blog/image-20230626165415599.png" alt="image-20230626163927774"></p><h3 id="_1-2-安装-windterm" tabindex="-1"><code>1.2</code> 安装 <code>WindTerm</code> <a class="header-anchor" href="#_1-2-安装-windterm" aria-label="Permalink to &quot;`1.2` 安装 `WindTerm`&quot;">​</a></h3><ul><li>每个安装包都带有 <code>Portable</code> 字样，表示 <code>免安装</code>，该压缩包解压后即可使用。把下载后的压缩包放到电脑里的某个目录，解压后，双击 <code>WindTerm.exe</code> 就可以运行了。</li></ul><p><img src="https://img.xbin.cn/blog/image-20230626170025229.png" alt="image-20230626165052676"></p><h3 id="_1-3-使用-windterm" tabindex="-1"><code>1.3</code> 使用 <code>WindTerm</code> <a class="header-anchor" href="#_1-3-使用-windterm" aria-label="Permalink to &quot;`1.3` 使用 `WindTerm`&quot;">​</a></h3><p>（<code>1</code>）双击 <code>WindTerm.exe</code></p><p>第一次启动程序，会需要选择一个目录存储配置等个人资料，这个根据个人喜好选择即可。</p><p><img src="https://img.xbin.cn/blog/image-20230626163927774.png" alt="image-20230626165250392"></p><p>（<code>2</code>）进入软件页面后</p><p><img src="https://img.xbin.cn/blog/image-20230626163815805.png" alt="image-20230626165415599"></p><p>（<code>3</code>）新建会话</p><p><img src="https://img.xbin.cn/blog/image-20230626165052676.png" alt="image-20230626165558433"></p><p>输入用户名：</p><p><img src="https://img.xbin.cn/blog/image-20230626170118190.png" alt="image-20230626170025229"></p><p>输入密码：</p><p><img src="https://img.xbin.cn/blog/image-20230626165558433.png" alt="image-20230626170118190"></p><p>连接效果：</p><p><img src="https://img.xbin.cn/blog/image-20230626170205586.png" alt="image-20230626170205586"></p><p>（<code>4</code>）上传文件</p><p>进入文件管理器</p><p><img src="https://img.xbin.cn/blog/image-20230626170700912.png" alt="image-20230626170700912"></p><p>选择要上传的文件进行上传</p><p><img src="https://img.xbin.cn/blog/image-20230626170802772.png" alt="image-20230626170802772"></p><p><img src="https://img.xbin.cn/blog/image-20230626170741327.png" alt="image-20230626170741327"></p>',35)])])}const h=o(c,[["render",t]]);export{s as __pageData,h as default};
